import { forwardRef, useCallback, useEffect, useId, useMemo, useRef, useState } from 'react';
import { getDefaultErrorMsg } from '@o9ds/utils';
import { useTooltip } from '../../hooks/useTooltip';
import { FormLabel } from '../FormLabel';
import O9IconButton from '../IconButton/IconButton';

export interface O9NumberInputProps
  extends Omit<
    React.InputHTMLAttributes<HTMLInputElement>,
    'size' | 'type' | 'value' | 'defaultValue' | 'onChange' | 'onInput'
  > {
  value?: number | null;
  defaultValue?: number | null;
  min?: number;
  max?: number;
  step?: number;
  placeholder?: string;
  isDisabled?: boolean;
  isReadOnly?: boolean;
  label?: string;
  isRequired?: boolean;
  isInvalid?: boolean;
  size?: 'sm' | 'lg';
  errorMsg?: string;
  isInlineError?: boolean;
  isLoading?: boolean;
  isFullWidth?: boolean;
  width?: string;
  onInput?: (event: React.FormEvent<HTMLInputElement>) => void;
  onChange?: (event: React.ChangeEvent<HTMLInputElement>) => void;
  onFocus?: (event: React.FocusEvent<HTMLInputElement>) => void;
  onBlur?: (event: React.FocusEvent<HTMLInputElement>) => void;
}

function getStepPrecision(step: number): number {
  const str = String(step);
  const dotIndex = str.indexOf('.');
  return dotIndex === -1 ? 0 : str.length - dotIndex - 1;
}

function clampAndRound(val: number, min?: number, max?: number, step?: number): number {
  if (min !== undefined && val < min) val = min;
  if (max !== undefined && val > max) val = max;
  const precision = step !== undefined ? getStepPrecision(step) : 0;
  return precision > 0 ? parseFloat(val.toFixed(precision)) : val;
}

const LONG_PRESS_DELAY = 400;
const LONG_PRESS_INTERVAL = 200;
const LONG_PRESS_FAST_INTERVAL = 50;
const LONG_PRESS_FAST_THRESHOLD = 10;

const O9NumberInput = forwardRef<HTMLDivElement, O9NumberInputProps>(
  function O9NumberInput(
    {
      value,
      defaultValue: defaultValueProp,
      min,
      max,
      step = 1,
      placeholder,
      isDisabled = false,
      isReadOnly = false,
      label,
      isRequired = false,
      isInvalid = false,
      size = 'lg',
      errorMsg,
      isInlineError = false,
      isLoading = false,
      isFullWidth = false,
      width,
      onInput,
      onChange,
      onFocus,
      onBlur,
      className,
      ...rest
    },
    ref
  ) {
    const uid = useId();
    const inputId = `o9ds-num-${uid}`;
    const errorId = `o9ds-num-err-${uid}`;
    const inputRef = useRef<HTMLInputElement>(null);
    const rootRef = useRef<HTMLDivElement | null>(null) as React.MutableRefObject<HTMLDivElement | null>;
    const fieldRef = useRef<HTMLDivElement>(null);
    const actionsRef = useRef<HTMLDivElement>(null);
    const errIcoRef = useRef<HTMLSpanElement>(null);

    const isControlled = value !== undefined;
    const [internalValue, setInternalValue] = useState<number | null>(defaultValueProp ?? null);

    const currentValue = isControlled ? value : internalValue;
    const errorMessage = errorMsg ?? getDefaultErrorMsg();
    useTooltip({
      triggerRef: errIcoRef,
      tooltip: isInlineError && isInvalid ? errorMessage : undefined,
    });

    // Dynamic padding + position for actions overlay
    const updatePadding = useCallback(() => {
      if (!actionsRef.current || !fieldRef.current) return;
      const w = actionsRef.current.offsetWidth;
      const pad = w > 0 ? w + 4 : 0;
      fieldRef.current.style.setProperty('--o9ds-number-input-pad-r', `${pad}px`);

      const steppers = fieldRef.current.querySelector('.o9ds-number-input__steppers');
      const steppersWidth = steppers ? (steppers as HTMLElement).offsetWidth : 0;
      actionsRef.current.style.right = `${steppersWidth}px`;
    }, []);

    useEffect(() => {
      updatePadding();
    });

    useEffect(() => {
      const el = actionsRef.current;
      if (!el) return;
      const obs = new ResizeObserver(updatePadding);
      obs.observe(el);
      return () => obs.disconnect();
    }, [updatePadding]);

    const atMin = min !== undefined && currentValue !== null && currentValue !== undefined && currentValue <= min;
    const atMax = max !== undefined && currentValue !== null && currentValue !== undefined && currentValue >= max;

    const classes = [
      'o9ds-number-input',
      `o9ds-number-input--${size}`,
      isFullWidth && 'o9ds-number-input--full-width',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      isReadOnly && 'is-readonly',
      isInvalid && 'has-error',
      isInvalid && isInlineError && 'error-inline',
      atMin && 'at-min',
      atMax && 'at-max',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    const dispatchCustomChange = useCallback(
      (newValue: number | null, previousValue: number | null) => {
        const rootEl = (ref as React.RefObject<HTMLDivElement>)?.current ?? rootRef.current;
        if (rootEl) {
          rootEl.dispatchEvent(
            new CustomEvent('number-input:change', {
              bubbles: true,
              detail: { value: newValue, previousValue },
            })
          );
        }
      },
      [ref]
    );

    function applyValue(newValue: number | null) {
      const previous = currentValue ?? null;
      if (!isControlled) {
        setInternalValue(newValue);
      }
      dispatchCustomChange(newValue, previous);

      // Synthesize a change event on the input element so consumers using onChange get notified
      const input = inputRef.current;
      if (input && onChange) {
        const nativeValueSetter = Object.getOwnPropertyDescriptor(
          window.HTMLInputElement.prototype,
          'value'
        )?.set;
        const strVal = newValue === null ? '' : String(newValue);
        nativeValueSetter?.call(input, strVal);
        input.dispatchEvent(new Event('change', { bubbles: true }));
      }
    }

    function increment(multiplier = 1) {
      const effectiveStep = step * multiplier;
      if (currentValue === null || currentValue === undefined) {
        const startVal = min ?? 0;
        applyValue(clampAndRound(startVal, min, max, step));
      } else {
        applyValue(clampAndRound(currentValue + effectiveStep, min, max, step));
      }
    }

    function decrement(multiplier = 1) {
      const effectiveStep = step * multiplier;
      if (currentValue === null || currentValue === undefined) {
        const startVal = max ?? 0;
        applyValue(clampAndRound(startVal, min, max, step));
      } else {
        applyValue(clampAndRound(currentValue - effectiveStep, min, max, step));
      }
    }

    // Long-press repeat logic
    const longPressRef = useRef<{
      timeout: ReturnType<typeof setTimeout> | null;
      interval: ReturnType<typeof setInterval> | null;
      repeatCount: number;
    }>({ timeout: null, interval: null, repeatCount: 0 });

    function clearLongPress() {
      const lp = longPressRef.current;
      if (lp.timeout) clearTimeout(lp.timeout);
      if (lp.interval) clearInterval(lp.interval);
      lp.timeout = null;
      lp.interval = null;
      lp.repeatCount = 0;
    }

    function startLongPress(action: () => void) {
      if (isDisabled || isLoading || isReadOnly) return;
      action();

      const lp = longPressRef.current;
      lp.timeout = setTimeout(() => {
        lp.interval = setInterval(() => {
          lp.repeatCount++;
          action();
          if (lp.repeatCount >= LONG_PRESS_FAST_THRESHOLD && lp.interval) {
            clearInterval(lp.interval);
            lp.interval = setInterval(action, LONG_PRESS_FAST_INTERVAL);
          }
        }, LONG_PRESS_INTERVAL);
      }, LONG_PRESS_DELAY);
    }

    useEffect(() => {
      return () => clearLongPress();
    }, []);

    function handleIncrementMouseDown(e: React.MouseEvent) {
      if (e.button !== 0) return;
      startLongPress(() => increment());
    }

    function handleDecrementMouseDown(e: React.MouseEvent) {
      if (e.button !== 0) return;
      startLongPress(() => decrement());
    }

    function handleStepperMouseUp() {
      clearLongPress();
      inputRef.current?.focus();
    }

    function handleStepperMouseLeave() {
      clearLongPress();
    }

    function handleIncrementTouchStart(e: React.TouchEvent) {
      e.preventDefault();
      startLongPress(() => increment());
    }

    function handleDecrementTouchStart(e: React.TouchEvent) {
      e.preventDefault();
      startLongPress(() => decrement());
    }

    function handleStepperTouchEnd() {
      clearLongPress();
      inputRef.current?.focus();
    }

    function handleInput(e: React.FormEvent<HTMLInputElement>) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        return;
      }
      onInput?.(e);
    }

    function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        return;
      }
      const raw = e.target.value;
      const parsed = raw === '' ? null : parseFloat(raw);
      const newValue = parsed === null ? null : isNaN(parsed) ? null : parsed;

      if (!isControlled) {
        setInternalValue(newValue);
      }
      dispatchCustomChange(newValue, currentValue ?? null);
      onChange?.(e);
    }

    function handleFocus(e: React.FocusEvent<HTMLInputElement>) {
      onFocus?.(e);
    }

    function handleBlur(e: React.FocusEvent<HTMLInputElement>) {
      if (!isDisabled && !isLoading && !isReadOnly) {
        const raw = e.target.value;
        if (raw !== '') {
          const parsed = parseFloat(raw);
          if (!isNaN(parsed)) {
            const clamped = clampAndRound(parsed, min, max, step);
            if (clamped !== parsed || raw !== String(clamped)) {
              e.target.value = String(clamped);
              if (!isControlled) {
                setInternalValue(clamped);
              }
              dispatchCustomChange(clamped, currentValue ?? null);

              if (onChange) {
                const nativeValueSetter = Object.getOwnPropertyDescriptor(
                  window.HTMLInputElement.prototype,
                  'value'
                )?.set;
                nativeValueSetter?.call(e.target, String(clamped));
                e.target.dispatchEvent(new Event('change', { bubbles: true }));
              }
            }
          }
        }
      }
      onBlur?.(e);
    }

    function handlePaste(e: React.ClipboardEvent<HTMLInputElement>) {
      if (isDisabled || isLoading || isReadOnly) return;
      const text = e.clipboardData.getData('text/plain');
      const parsed = parseFloat(text);
      if (isNaN(parsed)) {
        e.preventDefault();
        return;
      }
      e.preventDefault();
      const clamped = clampAndRound(parsed, min, max, step);
      const input = e.currentTarget;
      input.value = String(clamped);

      if (!isControlled) {
        setInternalValue(clamped);
      }
      dispatchCustomChange(clamped, currentValue ?? null);

      if (onChange) {
        const nativeValueSetter = Object.getOwnPropertyDescriptor(
          window.HTMLInputElement.prototype,
          'value'
        )?.set;
        nativeValueSetter?.call(input, String(clamped));
        input.dispatchEvent(new Event('change', { bubbles: true }));
      }
    }

    function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
      if (isDisabled || isLoading || isReadOnly) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }

      const isShift = e.shiftKey;

      switch (e.key) {
        case 'ArrowUp':
          e.preventDefault();
          increment(isShift ? 10 : 1);
          break;
        case 'ArrowDown':
          e.preventDefault();
          decrement(isShift ? 10 : 1);
          break;
        case 'Home':
          if (min !== undefined) {
            e.preventDefault();
            applyValue(min);
          }
          break;
        case 'End':
          if (max !== undefined) {
            e.preventDefault();
            applyValue(max);
          }
          break;
      }
    }

    const inputValueStr =
      currentValue === null || currentValue === undefined ? '' : String(currentValue);

    const ariaValueNow =
      currentValue === null || currentValue === undefined ? undefined : currentValue;

    const rootStyle: React.CSSProperties | undefined = useMemo(() => {
      const effectiveWidth = isFullWidth ? '100%' : width;
      if (!effectiveWidth) return undefined;
      return { '--o9ds-form-input-width': effectiveWidth } as React.CSSProperties;
    }, [isFullWidth, width]);

    return (
      <div
        ref={(node) => {
          rootRef.current = node;
          if (typeof ref === 'function') ref(node);
          else if (ref) (ref as React.MutableRefObject<HTMLDivElement | null>).current = node;
        }}
        className={classes}
        style={rootStyle}
        role="group"
        aria-busy={isLoading || undefined}
      >
        {label && (
          <FormLabel
            htmlFor={inputId}
            size="sm"
            isRequired={isRequired}
            isDisabled={isDisabled}
            className="o9ds-number-input__lbl"
          >
            {label}
          </FormLabel>
        )}
        <div ref={fieldRef} className="o9ds-number-input__field">
          <input
            ref={inputRef}
            id={inputId}
            type="number"
            className="o9ds-number-input__input"
            role="spinbutton"
            value={inputValueStr}
            placeholder={placeholder}
            disabled={isDisabled}
            readOnly={isReadOnly}
            required={isRequired}
            min={min}
            max={max}
            step={step}
            aria-valuenow={ariaValueNow}
            aria-valuemin={min}
            aria-valuemax={max}
            aria-invalid={isInvalid || undefined}
            aria-required={isRequired || undefined}
            aria-describedby={isInvalid ? errorId : undefined}
            onInput={handleInput}
            onChange={handleChange}
            onFocus={handleFocus}
            onBlur={handleBlur}
            onKeyDown={handleKeyDown}
            onPaste={handlePaste}
            {...rest}
          />
          <div ref={actionsRef} className="o9ds-number-input__actions">
            {isInlineError && isInvalid && (
              <span ref={errIcoRef} className="o9ds-number-input__err-ico" aria-hidden="true" />
            )}
          </div>
          {!isReadOnly && (
            <div className="o9ds-number-input__steppers">
              <O9IconButton
                size="sm"
                variant="tertiary"
                icon="angle-up"
                aria-label="Increment" // TODO: add translation support
                tooltip='Increment' // TODO: add translation support
                tabIndex={-1}
                aria-disabled={atMax || undefined}
                isDisabled={isDisabled || isLoading}
                onMouseDown={handleIncrementMouseDown}
                onMouseUp={handleStepperMouseUp}
                onMouseLeave={handleStepperMouseLeave}
                onTouchStart={handleIncrementTouchStart}
                onTouchEnd={handleStepperTouchEnd}
                className="o9ds-number-input__increment-btn"
              />
              <O9IconButton
                size="sm"
                variant="tertiary"
                icon="angle-down"
                aria-label="Decrement" // TODO: add translation support
                tooltip='Decrement' // TODO: add translation support
                tabIndex={-1}
                aria-disabled={atMin || undefined}
                isDisabled={isDisabled || isLoading}
                onMouseDown={handleDecrementMouseDown}
                onMouseUp={handleStepperMouseUp}
                onMouseLeave={handleStepperMouseLeave}
                onTouchStart={handleDecrementTouchStart}
                onTouchEnd={handleStepperTouchEnd}
                className="o9ds-number-input__decrement-btn"
              />
            </div>
          )}
          <div className="o9ds-number-input__border" />
        </div>
        {isInvalid && !isInlineError && (
          <div className="o9ds-inline-alert o9ds-inline-alert--error" id={errorId} role="alert">
            <span className="o9ds-inline-alert__ico" aria-hidden="true" />
            <span className="o9ds-inline-alert__msg">{errorMessage}</span>
          </div>
        )}
      </div>
    );
  }
);

export default O9NumberInput;
